import torch
import torch.nn as nn
from transformers import AutoModel, AutoTokenizer

class RewardModel(nn.Module):
    def __init__(self, base_model_id: str):
        super().__init__()
        self.backbone = AutoModel.from_pretrained(base_model_id)
        hidden = self.backbone.config.hidden_size
        self.head = nn.Linear(hidden, 1, bias=False)

    def forward(self, input_ids, attention_mask):
        out = self.backbone(input_ids=input_ids, attention_mask=attention_mask)
        # Use the last token's hidden state (EOS token for causal LMs)
        last_hidden = out.last_hidden_state[:, -1, :]
        return self.head(last_hidden).squeeze(-1)  # shape: (batch,)


def bt_loss(reward_model, chosen_ids, chosen_mask, rejected_ids, rejected_mask):
    r_w = reward_model(chosen_ids, chosen_mask)
    r_l = reward_model(rejected_ids, rejected_mask)
    return -torch.log(torch.sigmoid(r_w - r_l)).mean()

def filter_by_score_gap(pairs: list[dict], min_gap: float = 2.0) -> list[dict]:
    return [p for p in pairs if p.get("score_gap", 999) >= min_gap]

# Or when constructing:
def make_pairs_filtered(row, min_gap: float = 2.0):
    comps = row['completions']
    pairs = []
    for i in range(len(comps)):
        for j in range(i+1, len(comps)):
            si = float(comps[i].get('overall_score') or 0)
            sj = float(comps[j].get('overall_score') or 0)
            gap = abs(si - sj)
            if gap < min_gap:
                continue
            chosen, rejected = (i, j) if si > sj else (j, i)
            pairs.append({
                "prompt": row["instruction"],
                "chosen": comps[chosen]["response"],
                "rejected": comps[rejected]["response"],
                "score_gap": gap,
            })
    return pairs
